import{_ as l,o as a,c as r,ae as d}from"./chunks/framework.DAK3ioSj.js";const b=JSON.parse('{"title":"Skill 生成技术","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-01-generation.md","filePath":"radar/category-01-generation.md"}'),e={name:"radar/category-01-generation.md"};function i(o,t,h,n,s,k){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="skill-生成技术" tabindex="-1">Skill 生成技术 <a class="header-anchor" href="#skill-生成技术" aria-label="Permalink to &quot;Skill 生成技术&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v1.0.0 <strong>创建日期</strong>: 2026-05-10 <strong>分类</strong>: Skill 生命周期 - 第一阶段 <strong>成熟度</strong>: 🟡 成长期 | 综合评分: 0.52</p></blockquote><hr><h2 id="一、技术概述" tabindex="-1">一、技术概述 <a class="header-anchor" href="#一、技术概述" aria-label="Permalink to &quot;一、技术概述&quot;">​</a></h2><p><strong>Skill 生成</strong>是 Skill 全生命周期的起点，是基于用户/场景的确定性任务需求，完成从需求拆解、逻辑定义、开发编码、标准化封装到合规校验的全流程工程化开发体系。</p><p>核心目标：构建高可用、高适配、低缺陷、可复用的标准化 Skill，实现 Skill &quot;出生即高质量&quot;。</p><hr><h2 id="二、核心技术领域" tabindex="-1">二、核心技术领域 <a class="header-anchor" href="#二、核心技术领域" aria-label="Permalink to &quot;二、核心技术领域&quot;">​</a></h2><h3 id="_2-1-文档解析" tabindex="-1">2.1 文档解析 <a class="header-anchor" href="#_2-1-文档解析" aria-label="Permalink to &quot;2.1 文档解析&quot;">​</a></h3><p>将 PDF、Markdown、URL 等多源文档中提取结构化知识，转化为 Skill 可用的指令。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>文档解析</td><td>从 PDF/HTML/Markdown 提取结构化内容</td><td>🟢 成熟</td></tr><tr><td>知识抽取</td><td>从非结构化文本中抽取实体、关系</td><td>🟡 成长期</td></tr><tr><td>多模态解析</td><td>支持图表、代码、表格等多模态内容</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-2-语义聚合" tabindex="-1">2.2 语义聚合 <a class="header-anchor" href="#_2-2-语义聚合" aria-label="Permalink to &quot;2.2 语义聚合&quot;">​</a></h3><p>去冗余、合相似、抽模式，减少 Skill 膨胀，提升召回率。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>去冗余</td><td>剔除重复内容和噪声信息</td><td>🟡 成长期</td></tr><tr><td>语义聚类</td><td>基于文本聚类将同类文档合并</td><td>🟡 成长期</td></tr><tr><td>模式抽取</td><td>提炼通用执行路径</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-3-渐进式生成" tabindex="-1">2.3 渐进式生成 <a class="header-anchor" href="#_2-3-渐进式生成" aria-label="Permalink to &quot;2.3 渐进式生成&quot;">​</a></h3><p>从自然语言描述逐步生成结构化 Skill，降低开发门槛。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>一句话生成</td><td>一句话描述生成完整 Skill</td><td>🟢 成熟</td></tr><tr><td>人机协作</td><td>人工审核 + AI 生成</td><td>🟢 成熟</td></tr><tr><td>自生成</td><td>Agent 基于执行经验自主生成</td><td>🔴 探索期</td></tr></tbody></table><h3 id="_2-4-批量去重" tabindex="-1">2.4 批量去重 <a class="header-anchor" href="#_2-4-批量去重" aria-label="Permalink to &quot;2.4 批量去重&quot;">​</a></h3><p>识别并合并高度相似的 Skills，控制 Skill 库规模。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>相似度检测</td><td>计算 Skill 间语义相似度</td><td>🟢 成熟</td></tr><tr><td>智能合并</td><td>合并相似 Skill 保留核心能力</td><td>🟡 成长期</td></tr><tr><td>模式识别</td><td>识别重复模式，减少冗余</td><td>🟡 成长期</td></tr></tbody></table><hr><h2 id="三、代表技术与项目" tabindex="-1">三、代表技术与项目 <a class="header-anchor" href="#三、代表技术与项目" aria-label="Permalink to &quot;三、代表技术与项目&quot;">​</a></h2><h3 id="_3-1-trace2skill" tabindex="-1">3.1 Trace2Skill <a class="header-anchor" href="#_3-1-trace2skill" aria-label="Permalink to &quot;3.1 Trace2Skill&quot;">​</a></h3><p>从执行轨迹中自动提取可复用技能。</p><p><strong>核心能力</strong>：</p><ul><li>分析成功执行轨迹</li><li>抽象通用执行路径</li><li>生成标准化 Skill 指令</li></ul><p><strong>适用场景</strong>：从成功案例中快速生成 Skill</p><h3 id="_3-2-d2skill" tabindex="-1">3.2 D2Skill <a class="header-anchor" href="#_3-2-d2skill" aria-label="Permalink to &quot;3.2 D2Skill&quot;">​</a></h3><p>双粒度动态技能库，驱动策略-技能协同进化。</p><p><strong>核心能力</strong>：</p><ul><li>策略粒度 + 技能粒度双层抽象</li><li>根据模型能力动态调整 Skill</li><li>持续迭代优化</li></ul><p><strong>适用场景</strong>：需要精细化控制的复杂任务</p><h3 id="_3-3-memento-skills" tabindex="-1">3.3 Memento-Skills <a class="header-anchor" href="#_3-3-memento-skills" aria-label="Permalink to &quot;3.3 Memento-Skills&quot;">​</a></h3><p>让 Agent 自主设计 Skill，实现自我进化。</p><p><strong>核心能力</strong>：</p><ul><li>从经验中提取 Skill</li><li>自主发现问题并生成新 Skill</li><li>自我验证与迭代</li></ul><p><strong>适用场景</strong>：需要 Agent 自主进化的场景</p><h3 id="_3-4-skillrl" tabindex="-1">3.4 SKILLRL <a class="header-anchor" href="#_3-4-skillrl" aria-label="Permalink to &quot;3.4 SKILLRL&quot;">​</a></h3><p>通过技能的强化学习促进 Agent 自进化。</p><p><strong>核心能力</strong>：</p><ul><li>差异化经验蒸馏</li><li>分层技能库构建</li><li>递归技能演化</li></ul><p><strong>链接</strong>：<a href="https://github.com/aiming-lab/SkillRL" target="_blank" rel="noreferrer">GitHub</a></p><h3 id="_3-5-skill-creator-2-0" tabindex="-1">3.5 Skill Creator 2.0 <a class="header-anchor" href="#_3-5-skill-creator-2-0" aria-label="Permalink to &quot;3.5 Skill Creator 2.0&quot;">​</a></h3><p>Anthropic 人机协作持续优化，使 Agent 能加载专业技能。</p><p><strong>核心能力</strong>：</p><ul><li>一句话生成 Skill</li><li>人工审核 + 自动优化</li><li>与 Claude Code 深度集成</li></ul><hr><h2 id="四、技术成熟度分析" tabindex="-1">四、技术成熟度分析 <a class="header-anchor" href="#四、技术成熟度分析" aria-label="Permalink to &quot;四、技术成熟度分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术</th><th>技术成熟度</th><th>创新性</th><th>落地程度</th><th>生态活跃度</th><th>综合</th></tr></thead><tbody><tr><td>文档解析</td><td>0.55</td><td>0.50</td><td>0.60</td><td>0.55</td><td>0.55</td></tr><tr><td>语义聚合</td><td>0.50</td><td>0.65</td><td>0.45</td><td>0.45</td><td>0.52</td></tr><tr><td>渐进式生成</td><td>0.65</td><td>0.55</td><td>0.70</td><td>0.75</td><td>0.66</td></tr><tr><td>批量去重</td><td>0.45</td><td>0.60</td><td>0.40</td><td>0.40</td><td>0.46</td></tr><tr><td><strong>阶段综合</strong></td><td><strong>0.50</strong></td><td><strong>0.70</strong></td><td><strong>0.40</strong></td><td><strong>0.45</strong></td><td><strong>0.52</strong></td></tr></tbody></table><hr><h2 id="五、学习资源" tabindex="-1">五、学习资源 <a class="header-anchor" href="#五、学习资源" aria-label="Permalink to &quot;五、学习资源&quot;">​</a></h2><ul><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】13-Trace2Skill：让智能体自己总结经验，自动生成可复用技能.html">Trace2Skill：让智能体自己总结经验，自动生成可复用技能</a></li><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】14-D2Skill：双粒度动态技能库，驱动策略-技能协同进化的新范式.html">D2Skill：双粒度动态技能库</a></li><li><a href="https://github.com/aiming-lab/SkillRL" target="_blank" rel="noreferrer">SKILLRL GitHub</a></li><li><a href="https://atomgit.com/openeuler/witty-skill-insight" target="_blank" rel="noreferrer">witty-skill-insight 项目</a></li></ul>',52)])])}const c=l(e,[["render",i]]);export{b as __pageData,c as default};
